# Set a rotation policy: rotate at 80% of the 90-day lifetime (72 days)
az keyvault secret set-attributes \
  --vault-name myKV \
  --name sp-client-secret \
  --policy '{
    "lifetimeActions": [
      {
        "action": { "type": "Rotate" },
        "trigger": { "timeAfterCreate": "P72D" }
      },
      {
        "action": { "type": "Notify" },
        "trigger": { "timeBeforeExpiry": "P10D" }
      }
    ],
    "attributes": { "expiryTime": "P90D" }
  }'

variable "rotation_timestamp" {
  description = "Update this value to trigger credential rotation"
  type        = string
  default     = "2026-01-01"
}

resource "azuread_application_password" "app_secret" {
  application_id = azuread_application.myapp.id
  display_name   = "rotated-${var.rotation_timestamp}"
  end_date       = timeadd(timestamp(), "2160h")  # 90 days

  rotate_when_changed = {
    rotation = var.rotation_timestamp
  }
}

resource "azurerm_key_vault_secret" "sp_secret" {
  name         = "sp-client-secret"
  value        = azuread_application_password.app_secret.value
  key_vault_id = azurerm_key_vault.myKV.id

  expiration_date = timeadd(timestamp(), "2160h")

  tags = {
    app_id = azuread_application.myapp.application_id
  }
}
